import { defineComponentSlotStyle } from "@yamada-ui/react"

export const actionBarStyle = defineComponentSlotStyle({
  base: {
    content: {
      alignItems: "center",
      bg: "bg.float",
      borderColor: "border",
      borderWidth: "1px",
      boxShadow: "lg",
      display: "flex",
      gap: "2",
      px: "2",
      py: "2",
      rounded: "l4",
    },
    root: {
      position: "fixed",
      zIndex: "burter",
    },
    separator: { bg: "border.emphasized", h: "8", w: "px" },
  },

  props: {
    /**
     * The placement of the action bar.
     *
     * @default 'end-center'
     */
    placement: {
      "end-center": {
        root: { bottom: "lg", left: "50%", transform: "translateX(-50%)" },
      },
      "end-end": {
        root: { bottom: "lg", right: "lg" },
      },
      "end-start": {
        root: { bottom: "lg", left: "lg" },
      },
      "start-center": {
        root: { left: "50%", top: "lg", transform: "translateX(-50%)" },
      },
      "start-end": {
        root: { right: "lg", top: "lg" },
      },
      "start-start": {
        root: { left: "lg", top: "lg" },
      },
    },
  },

  defaultProps: {
    placement: "end-center",
  },
})

export type ActionBarStyle = typeof actionBarStyle

import type { FC } from "react"
import { a11y, page, render } from "#test/browser"
import { ActionBar } from "."
import { Button } from "../button"
import { CloseButton } from "../close-button"

const TestComponent: FC<ActionBar.RootProps> = (props) => {
  return (
    <ActionBar.Root data-testid="root" {...props}>
      <ActionBar.OpenTrigger>
        <Button data-testid="openTrigger">Open ActionBar</Button>
      </ActionBar.OpenTrigger>

      <ActionBar.Content data-testid="content">
        <Button variant="outline" borderStyle="dashed">
          2 Selected
        </Button>
        <ActionBar.Separator data-testid="separator" />
        <ActionBar.CloseTrigger>
          <CloseButton size="md" data-testid="closeTrigger" />
        </ActionBar.CloseTrigger>
      </ActionBar.Content>
    </ActionBar.Root>
  )
}

describe("<ActionBar />", () => {
  test("renders component correctly", async () => {
    await a11y(<TestComponent />)
  })

  test("sets `displayName` correctly", () => {
    expect(ActionBar.Root.displayName).toBe("ActionBarRoot")
    expect(ActionBar.OpenTrigger.displayName).toBe("ActionBarOpenTrigger")
    expect(ActionBar.Content.displayName).toBe("ActionBarContent")
    expect(ActionBar.Separator.displayName).toBe("ActionBarSeparator")
    expect(ActionBar.CloseTrigger.displayName).toBe("ActionBarCloseTrigger")
  })

  test("sets `className` correctly", async () => {
    await render(<TestComponent open />)

    await expect
      .element(page.getByTestId("root"))
      .toHaveClass("ui-action-bar__root")
    await expect
      .element(page.getByTestId("content"))
      .toHaveClass("ui-action-bar__content")
    await expect
      .element(page.getByTestId("openTrigger"))
      .toHaveClass("ui-action-bar__trigger--open")
    await expect
      .element(page.getByTestId("closeTrigger"))
      .toHaveClass("ui-action-bar__trigger--close")
    await expect
      .element(page.getByTestId("separator"))
      .toHaveClass("ui-action-bar__separator")
  })

  test("renders HTML tag correctly", async () => {
    await render(<TestComponent open />)

    expect(page.getByTestId("root").element().tagName).toBe("DIV")
    expect(page.getByTestId("content").element().tagName).toBe("SECTION")
    expect(page.getByTestId("separator").element().tagName).toBe("DIV")
  })

  test("sets aria attributes correctly", async () => {
    await render(<TestComponent open />)

    await expect
      .element(page.getByTestId("openTrigger"))
      .toHaveAttribute("aria-controls")
    await expect
      .element(page.getByTestId("openTrigger"))
      .toHaveAttribute("aria-expanded", "true")
    await expect
      .element(page.getByTestId("openTrigger"))
      .toHaveAttribute("aria-haspopup", "dialog")
    await expect
      .element(page.getByTestId("openTrigger"))
      .toHaveAttribute("aria-label", "Open action bar")
    await expect
      .element(page.getByTestId("closeTrigger"))
      .toHaveAttribute("aria-label", "Close action bar")
    await expect
      .element(page.getByTestId("content"))
      .toHaveAttribute("role", "dialog")
    await expect.element(page.getByTestId("content")).toHaveAttribute("id")
  })

  test("opens action bar when open trigger is clicked", async () => {
    const { user } = await render(<TestComponent />)

    expect(document.querySelector('[data-testid="content"]')).toBeNull()

    await user.click(page.getByTestId("openTrigger"))
    await expect.element(page.getByTestId("content")).toBeVisible()
  })

  test("closes action bar when close trigger is clicked", async () => {
    const { user } = await render(<TestComponent defaultOpen />)

    await expect.element(page.getByTestId("content")).toBeVisible()

    await user.click(page.getByTestId("closeTrigger"))

    await vi.waitFor(() => {
      expect(document.querySelector('[data-testid="content"]')).toBeNull()
    })
  })

  test("closes action bar when Escape key is pressed", async () => {
    const onClose = vi.fn()

    await render(<TestComponent open onClose={onClose} />)

    document.dispatchEvent(
      new KeyboardEvent("keydown", { key: "Escape", bubbles: true }),
    )

    expect(onClose).toHaveBeenCalledOnce()
  })

  test("does not close action bar when Escape is pressed and `closeOnEsc` is false", async () => {
    const onClose = vi.fn()

    await render(<TestComponent closeOnEsc={false} open onClose={onClose} />)

    document.dispatchEvent(
      new KeyboardEvent("keydown", { key: "Escape", bubbles: true }),
    )

    expect(onClose).not.toHaveBeenCalled()
  })

  test("does not close action bar when a non-Escape key is pressed", async () => {
    const onClose = vi.fn()

    await render(<TestComponent open onClose={onClose} />)

    document.dispatchEvent(
      new KeyboardEvent("keydown", { key: "Enter", bubbles: true }),
    )

    expect(onClose).not.toHaveBeenCalled()
  })

  test("renders with shorthand `content` and `trigger` props", async () => {
    await render(
      <ActionBar.Root
        content={<p data-testid="shorthand-content">Content</p>}
        open
        trigger={<Button data-testid="shorthand-trigger">Open</Button>}
      />,
    )

    await expect.element(page.getByTestId("shorthand-trigger")).toBeVisible()
    await expect.element(page.getByTestId("shorthand-content")).toBeVisible()
  })

  test("calls onCloseComplete after exit animation", async () => {
    const onCloseComplete = vi.fn()
    const { rerender } = await render(
      <TestComponent open onCloseComplete={onCloseComplete} />,
    )

    rerender(<TestComponent open={false} onCloseComplete={onCloseComplete} />)

    await vi.waitFor(() => {
      expect(onCloseComplete).toHaveBeenCalledOnce()
    })
  })

  test("renders with `start` placement", async () => {
    await render(<TestComponent open placement="start-center" />)

    await expect.element(page.getByTestId("content")).toBeVisible()
  })

  test("renders children as fallback when no `content` prop or ActionBar.Content", async () => {
    await render(
      <ActionBar.Root open>
        <p data-testid="fallback">Fallback children</p>
      </ActionBar.Root>,
    )

    await expect.element(page.getByTestId("fallback")).toBeVisible()
  })

  test("sets `aria-expanded` to false and no `aria-controls` when closed", async () => {
    await render(<TestComponent />)

    await expect
      .element(page.getByTestId("openTrigger"))
      .toHaveAttribute("aria-expanded", "false")
    await expect
      .element(page.getByTestId("openTrigger"))
      .not.toHaveAttribute("aria-controls")
  })
})

"use client"

import type { PropsWithChildren, ReactNode } from "react"
import type { HTMLProps, HTMLStyledProps, ThemeProps } from "@yamada-ui/react"
import type { HTMLMotionPropsWithoutAs } from "../motion"
import type { UsePopupAnimationProps } from "../popover"
import type { ActionBarStyle } from "./action-bar.style"
import type { UseActionBarProps, UseActionBarReturn } from "./use-action-bar"
import { AnimatePresence } from "motion/react"
import { useMemo } from "react"
import { createSlotComponent, styled, cast, useSplitChildren } from "@yamada-ui/react"
import { useValue } from "../../hooks/use-value"
import { motion } from "../motion"
import { usePopupAnimationProps } from "../popover"
import { Portal, type PortalProps } from "../portal"
import { actionBarStyle } from "./action-bar.style"
import { useActionBar } from "./use-action-bar"

interface ComponentContext
  extends
    Pick<
      UseActionBarReturn,
      "getCloseTriggerProps" | "getContentProps" | "getOpenTriggerProps"
    >,
    Pick<ActionBarRootProps, "animationScheme" | "duration"> {}

export interface ActionBarRootProps
  extends
    Omit<HTMLStyledProps, "content">,
    ThemeProps<ActionBarStyle>,
    UseActionBarProps,
    UsePopupAnimationProps {
  /**
   * The action bar content to use.
   */
  content?: ReactNode
  /**
   * The action bar trigger to use.
   */
  trigger?: ReactNode
  /**
   * Props to be forwarded to the portal component.
   */
  portalProps?: Omit<PortalProps, "children">
  /**
   * Callback function to run side effects after the action bar has closed.
   */
  onCloseComplete?: () => void
}

const {
  ComponentContext,
  PropsContext: ActionBarPropsContext,
  useComponentContext,
  usePropsContext: useActionBarPropsContext,
  withContext,
  withProvider,
} = createSlotComponent<ActionBarRootProps, ActionBarStyle, ComponentContext>(
  "action-bar",
  actionBarStyle,
)

export { ActionBarPropsContext, useActionBarPropsContext }

/**
 * `ActionBar` is a component that is used to display a bottom action bar with a set of actions.
 *
 * @see https://yamada-ui.com/docs/components/action-bar
 */
export const ActionBarRoot = withProvider<
  "div",
  ActionBarRootProps,
  "placement"
>(
  ({
    animationScheme,
    children,
    content: contentProp,
    duration,
    placement: placementProp,
    trigger,
    portalProps,
    onCloseComplete,
    ...rest
  }) => {
    const placement = useValue(placementProp)

    animationScheme ??= placement?.startsWith("start")
      ? "block-start"
      : "block-end"

    const [omittedChildren, openTrigger, content] = useSplitChildren(
      children,
      ActionBarOpenTrigger,
      ActionBarContent,
    )
    const {
      open,
      getCloseTriggerProps,
      getContentProps,
      getOpenTriggerProps,
      getRootProps,
    } = useActionBar(rest)
    const customOpenTrigger = trigger ? (
      <ActionBarOpenTrigger>{trigger}</ActionBarOpenTrigger>
    ) : null
    const customContent = contentProp ? (
      <ActionBarContent>{contentProp}</ActionBarContent>
    ) : null
    const context = useMemo(
      () => ({
        animationScheme,
        duration,
        getCloseTriggerProps,
        getContentProps,
        getOpenTriggerProps,
      }),
      [
        animationScheme,
        duration,
        getCloseTriggerProps,
        getContentProps,
        getOpenTriggerProps,
      ],
    )

    return (
      <ComponentContext value={context}>
        {openTrigger ?? customOpenTrigger}

        <AnimatePresence onExitComplete={onCloseComplete}>
          {open ? (
            <Portal {...portalProps}>
              <styled.div {...getRootProps()}>
                {content ?? customContent ?? omittedChildren}
              </styled.div>
            </Portal>
          ) : null}
        </AnimatePresence>
      </ComponentContext>
    )
  },
  "root",
  { transferProps: ["placement"] },
)()

export interface ActionBarOpenTriggerProps extends HTMLStyledProps<"button"> {}

export const ActionBarOpenTrigger = withContext<
  "button",
  ActionBarOpenTriggerProps
>("button", { name: "OpenTrigger", slot: ["trigger", "open"] })(
  undefined,
  (props) => {
    const { getOpenTriggerProps } = useComponentContext()

    return { asChild: true, ...getOpenTriggerProps(props) }
  },
)

export interface ActionBarCloseTriggerProps extends HTMLStyledProps<"button"> {}

export const ActionBarCloseTrigger = withContext<
  "button",
  ActionBarCloseTriggerProps
>("button", { name: "CloseTrigger", slot: ["trigger", "close"] })(
  undefined,
  (props) => {
    const { getCloseTriggerProps } = useComponentContext()

    return { asChild: true, ...getCloseTriggerProps(props) }
  },
)

export interface ActionBarContentProps
  extends Omit<HTMLStyledProps<"section">, "children">, PropsWithChildren {}

export const ActionBarContent = withContext<"section", ActionBarContentProps>(
  (props) => {
    const { animationScheme, duration, getContentProps } = useComponentContext()
    const popupAnimationProps = usePopupAnimationProps({
      animationScheme,
      duration,
    })

    return (
      <motion.section
        {...popupAnimationProps}
        {...cast<HTMLMotionPropsWithoutAs<"section">>(
          getContentProps(cast<HTMLProps<"section">>(props)),
        )}
      />
    )
  },
  "content",
)()

export interface ActionBarSeparatorProps extends HTMLStyledProps {}

export const ActionBarSeparator = withContext<"div", ActionBarSeparatorProps>(
  "div",
  "separator",
)()

"use client"

import type { HTMLProps, PropGetter } from "@yamada-ui/react"
import { useCallback } from "react"
import {
  mergeProps,
  useEnvironment,
  handlerAll,
  useIds,
} from "@yamada-ui/react"
import {
  useDisclosure,
  type UseDisclosureProps,
} from "../../hooks/use-disclosure"
import { useEventListener } from "../../hooks/use-event-listener"
import { useI18n } from "../../providers/i18n-provider"

export interface UseActionBarProps
  extends HTMLProps, Omit<UseDisclosureProps, "timing"> {
  /**
   * If `true`, the action bar will close when the `Esc` key is pressed.
   *
   * @default true
   */
  closeOnEsc?: boolean
}

export const useActionBar = ({
  closeOnEsc = true,
  defaultOpen,
  open: openProp,
  onClose: onCloseProp,
  onOpen: onOpenProp,
  ...rest
}: UseActionBarProps = {}) => {
  const { getDocument } = useEnvironment()
  const { open, onClose, onOpen } = useDisclosure({
    defaultOpen,
    open: openProp,
    onClose: onCloseProp,
    onOpen: onOpenProp,
  })
  const [contentId] = useIds()
  const { t } = useI18n("actionBar")

  const onKeyDown = useCallback(
    (ev: KeyboardEvent) => {
      if (ev.key !== "Escape") return

      if (!closeOnEsc) return

      ev.stopPropagation()
      onClose()
    },
    [closeOnEsc, onClose],
  )

  useEventListener(getDocument(), "keydown", onKeyDown)

  const getRootProps: PropGetter = useCallback(
    (props = {}) => mergeProps(rest, props)(),
    [rest],
  )

  const getOpenTriggerProps: PropGetter<"button"> = useCallback(
    (props = {}) => ({
      "aria-controls": open ? contentId : undefined,
      "aria-expanded": open,
      "aria-haspopup": "dialog",
      "aria-label": t("Open action bar"),
      ...props,
      onClick: handlerAll(props.onClick, onOpen),
    }),
    [contentId, onOpen, open, t],
  )

  const getCloseTriggerProps: PropGetter<"button"> = useCallback(
    (props = {}) => ({
      "aria-label": t("Close action bar"),
      ...props,
      onClick: handlerAll(props.onClick, onClose),
    }),
    [onClose, t],
  )

  const getContentProps: PropGetter<"section"> = useCallback(
    (props = {}) => ({
      id: contentId,
      role: "dialog",
      ...props,
    }),
    [contentId],
  )

  return {
    open,
    getCloseTriggerProps,
    getContentProps,
    getOpenTriggerProps,
    getRootProps,
    onClose,
    onOpen,
  }
}

export type UseActionBarReturn = ReturnType<typeof useActionBar>
